import React, { useState, useEffect } from 'react';
import API from '../api/axios';
import Navigation from '../components/Navigation';

const ProgrammeMaster = () => {
    const [programmes, setProgrammes] = useState([]);
    const [departments, setDepartments] = useState([]);
    const [formData, setFormData] = useState({ department: '', programmeName: '', programmeShortName: '' });
    const [loading, setLoading] = useState(false);
    const [message, setMessage] = useState('');
    const [deptLoading, setDeptLoading] = useState(true);

    useEffect(() => {
        fetchProgrammes();
        fetchDepartments();
    }, []);

    const fetchProgrammes = async () => {
        try {
            const { data } = await API.get('/master/programme');
            setProgrammes(data);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error fetching programmes' });
        }
    };

    const fetchDepartments = async () => {
        try {
            const { data } = await API.get('/master/department');
            console.log('Departments API Response:', data); // Debug log
            // Sort departments alphabetically for better UX
            const sortedDepartments = data.sort((a, b) => 
                (a.department || a.deptName || '').localeCompare(b.department || b.deptName || '')
            );
            setDepartments(sortedDepartments);
        } catch (err) {
            console.error('Error fetching departments:', err); // Debug log
            setMessage({ type: 'error', text: 'Error fetching departments' });
        } finally {
            setDeptLoading(false);
        }
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setLoading(true);
        try {
            await API.post('/master/programme', formData);
            setFormData({ department: '', programmeName: '', programmeShortName: '' });
            fetchProgrammes();
            setMessage({ type: 'success', text: '✓ Programme added successfully!' });
            setTimeout(() => setMessage(''), 3000);
        } catch (err) {
            setMessage({ type: 'error', text: 'Error adding programme' });
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.pageWrapper}>
            <Navigation />
            <div style={styles.contentArea}>
                <div style={styles.headerSection}>
                    <h1 style={styles.mainTitle}>📚 Programme Master</h1>
                    <p style={styles.subtitle}>Manage all academic programmes</p>
                </div>

                {message && (
                    <div style={{
                        ...styles.alertBox,
                        background: message.type === 'success' 
                            ? '#f0fdf4' 
                            : '#fef2f2',
                        borderColor: message.type === 'success' ? '#22c55e' : '#ef4444',
                        color: message.type === 'success' ? '#15803d' : '#dc2626',
                    }}>
                        {message.text}
                    </div>
                )}

                <div style={styles.container}>
                    <div style={styles.formSide}>
                        <div style={styles.formHeader}>
                            <h3 style={styles.formTitle}>Add New Programme</h3>
                            <div style={styles.deptCount}>
                                📁 {departments.length} departments available
                            </div>
                        </div>
                        
                        <form onSubmit={handleSubmit} style={styles.form}>
                            <div style={styles.formGroup}>
                                <label style={styles.label}>
                                    <span style={styles.labelIcon}>🏛️</span>
                                    Select Department
                                </label>
                                {deptLoading ? (
                                    <div style={styles.loadingPlaceholder}>
                                        <span style={styles.spinner}>⏳</span> Loading departments...
                                    </div>
                                ) : (
                                    <select 
                                        required
                                        value={formData.department}
                                        onChange={e => setFormData({...formData, department: e.target.value})}
                                        style={styles.select}
                                    >
                                        <option value="">-- Select a department --</option>
                                        {departments.map(dept => {
                                            // Handle different department field names
                                            const deptName = dept.department || dept.deptName || dept.name || 'Unnamed Department';
                                            return (
                                                <option key={dept._id} value={dept._id} style={styles.option}>
                                                    {deptName}
                                                </option>
                                            );
                                        })}
                                    </select>
                                )}
                                <div style={styles.helperText}>
                                    {departments.length === 0 && !deptLoading ? 
                                        "⚠️ No departments found. Please add departments first." : 
                                        "Select from available departments"}
                                </div>
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>
                                    <span style={styles.labelIcon}>📖</span>
                                    Programme Name
                                </label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.programmeName}
                                    onChange={e => setFormData({...formData, programmeName: e.target.value})}
                                    style={styles.input}
                                    placeholder="Enter full programme name..."
                                    disabled={deptLoading || departments.length === 0}
                                />
                                <div style={styles.helperText}>
                                    e.g., Bachelor of Computer Applications, Master of Arts in English
                                </div>
                            </div>
                            
                            <div style={styles.formGroup}>
                                <label style={styles.label}>
                                    <span style={styles.labelIcon}>🏷️</span>
                                    Short Name / Code
                                </label>
                                <input 
                                    type="text" 
                                    required
                                    value={formData.programmeShortName}
                                    onChange={e => setFormData({...formData, programmeShortName: e.target.value})}
                                    style={styles.input}
                                    placeholder="BCA, MA, B.Sc..."
                                    maxLength="10"
                                    disabled={deptLoading || departments.length === 0}
                                />
                                <div style={styles.helperText}>
                                    Short code for the programme (max 10 characters)
                                </div>
                            </div>

                            <button 
                                type="submit" 
                                disabled={loading || deptLoading || departments.length === 0} 
                                style={{
                                    ...styles.button, 
                                    opacity: (loading || deptLoading || departments.length === 0) ? 0.6 : 1,
                                    cursor: (loading || deptLoading || departments.length === 0) ? 'not-allowed' : 'pointer'
                                }}
                            >
                                {loading ? (
                                    <>
                                        <span style={styles.buttonIcon}>⏳</span> Adding Programme...
                                    </>
                                ) : (
                                    <>
                                        <span style={styles.buttonIcon}>➕</span> Add Programme
                                    </>
                                )}
                            </button>
                        </form>
                    </div>

                    <div style={styles.tableSide}>
                        <div style={styles.tableHeader}>
                            <h3 style={styles.tableTitle}>📋 Programme List</h3>
                            <div style={styles.progCount}>
                                📚 {programmes.length} programme{programmes.length !== 1 ? 's' : ''}
                            </div>
                        </div>
                        
                        <div style={styles.tableContainer}>
                            {programmes.length === 0 ? (
                                <div style={styles.emptyState}>
                                    <div style={styles.emptyIcon}>📚</div>
                                    <h4 style={styles.emptyTitle}>No Programmes Yet</h4>
                                    <p style={styles.emptyText}>
                                        Add your first programme using the form on the left.
                                    </p>
                                </div>
                            ) : (
                                <table style={styles.table}>
                                    <thead>
                                        <tr style={styles.tableHeaderRow}>
                                            <th style={styles.tableHeader}>Department</th>
                                            <th style={styles.tableHeader}>Programme Name</th>
                                            <th style={styles.tableHeader}>Short Name</th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        {programmes.map((prog, idx) => {
                                            const deptName = prog.department?.deptName || 
                                                           prog.department?.department || 
                                                           prog.department?.name || 
                                                           'N/A';
                                            return (
                                                <tr key={prog._id} style={idx % 2 === 0 ? styles.tableRowEven : styles.tableRowOdd}>
                                                    <td style={styles.tableCell}>
                                                        <div style={styles.deptCell}>
                                                            <span style={styles.deptIcon}>🏛️</span>
                                                            {deptName}
                                                        </div>
                                                    </td>
                                                    <td style={styles.tableCell}>
                                                        <div style={styles.progName}>
                                                            {prog.programmeName}
                                                        </div>
                                                    </td>
                                                    <td style={styles.tableCell}>
                                                        <span style={styles.badge}>
                                                            {prog.programmeShortName}
                                                        </span>
                                                    </td>
                                                </tr>
                                            );
                                        })}
                                    </tbody>
                                </table>
                            )}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

const styles = {
